import React, { useState } from 'react';
import auth from '../services/auth';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const res = await auth.login(email, password);
    setLoading(false);
    if (res.ok) {
      window.location.href = '/';
    } else {
      setError(res.message || 'Login failed');
    }
  }

  return (
    <div className="login-container" style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#020617',
      position: 'relative',
      overflow: 'hidden',
      padding: '24px'
    }}>
      {/* Dynamic Background Elements */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'radial-gradient(circle at 20% 30%, rgba(99, 102, 241, 0.15) 0%, transparent 50%), radial-gradient(circle at 80% 70%, rgba(139, 92, 246, 0.15) 0%, transparent 50%)',
        zIndex: 0
      }}></div>

      <div className="floating-blob" style={{
        position: 'absolute',
        width: '500px',
        height: '500px',
        background: 'rgba(99, 102, 241, 0.1)',
        borderRadius: '50%',
        filter: 'blur(100px)',
        top: '10%',
        left: '10%',
        animation: 'float 20s infinite alternate'
      }}></div>

      <div className="floating-blob" style={{
        position: 'absolute',
        width: '400px',
        height: '400px',
        background: 'rgba(139, 92, 246, 0.1)',
        borderRadius: '50%',
        filter: 'blur(80px)',
        bottom: '10%',
        right: '10%',
        animation: 'float 25s infinite alternate-reverse'
      }}></div>

      <div className="login-card fade-in" style={{
        width: '100%',
        maxWidth: '480px',
        background: 'rgba(15, 23, 42, 0.6)',
        backdropFilter: 'blur(40px)',
        WebkitBackdropFilter: 'blur(40px)',
        padding: '4rem 3.5rem',
        borderRadius: '40px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5), inset 0 0 0 1px rgba(255, 255, 255, 0.1)',
        border: '1px solid rgba(255, 255, 255, 0.1)',
        position: 'relative',
        zIndex: 1
      }}>
        <div style={{ textAlign: 'center', marginBottom: '3.5rem' }}>
          <div style={{
            width: '100px',
            height: '100px',
            margin: '0 auto 2rem',
            background: 'linear-gradient(135deg, #6366f1 0%, #a855f7 100%)',
            borderRadius: '30px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '52px',
            boxShadow: '0 20px 40px rgba(99, 102, 241, 0.4)',
            transform: 'rotate(-5deg)',
            animation: 'pulse 4s infinite'
          }}>
            🔐
          </div>
          <h1 style={{
            fontSize: '2.75rem',
            fontWeight: '900',
            color: 'white',
            margin: 0,
            marginBottom: '0.75rem',
            letterSpacing: '-0.04em',
            background: 'linear-gradient(to bottom, #fff, #94a3b8)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}>
            Admin Access
          </h1>
          <p style={{ margin: 0, color: '#94a3b8', fontSize: '1.125rem', fontWeight: '500' }}>
            Harari Saving & Credit Management
          </p>
        </div>

        <form onSubmit={submit} style={{ display: 'grid', gap: '2rem' }}>
          <div className="input-group">
            <label style={{
              display: 'block',
              fontSize: '0.875rem',
              fontWeight: '700',
              color: '#e2e8f0',
              marginBottom: '0.75rem',
              marginLeft: '0.5rem',
              textTransform: 'uppercase',
              letterSpacing: '0.05em'
            }}>
              Email Address
            </label>
            <div style={{ position: 'relative' }}>
              <span style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: '#64748b' }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
                  <polyline points="22,6 12,13 2,6" />
                </svg>
              </span>
              <input
                type="email"
                placeholder="admin@harari.com"
                value={email}
                onChange={e => setEmail(e.target.value)}
                required
                style={{
                  width: '100%',
                  padding: '1.125rem 1.25rem 1.125rem 3.5rem',
                  borderRadius: '20px',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  background: 'rgba(0, 0, 0, 0.3)',
                  color: 'white',
                  fontSize: '1rem',
                  transition: 'all 0.3s ease',
                  outline: 'none'
                }}
                className="login-input"
              />
            </div>
          </div>

          <div className="input-group">
            <label style={{
              display: 'block',
              fontSize: '0.875rem',
              fontWeight: '700',
              color: '#e2e8f0',
              marginBottom: '0.75rem',
              marginLeft: '0.5rem',
              textTransform: 'uppercase',
              letterSpacing: '0.05em'
            }}>
              Password
            </label>
            <div style={{ position: 'relative' }}>
              <span style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: '#64748b' }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                </svg>
              </span>
              <input
                type={showPassword ? "text" : "password"}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                required
                style={{
                  width: '100%',
                  padding: '1.125rem 3.5rem 1.125rem 3.5rem',
                  borderRadius: '20px',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  background: 'rgba(0, 0, 0, 0.3)',
                  color: 'white',
                  fontSize: '1rem',
                  transition: 'all 0.3s ease',
                  outline: 'none'
                }}
                className="login-input"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: 'absolute',
                  right: '1.25rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: '#64748b',
                  cursor: 'pointer',
                  padding: '0.5rem',
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'color 0.2s'
                }}
              >
                {showPassword ? (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" />
                    <line x1="1" y1="1" x2="23" y2="23" />
                  </svg>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
                    <circle cx="12" cy="12" r="3" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <button
            disabled={loading}
            type="submit"
            style={{
              width: '100%',
              padding: '1.25rem',
              background: loading ? 'rgba(99, 102, 241, 0.5)' : 'linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)',
              color: 'white',
              border: 'none',
              borderRadius: '20px',
              fontWeight: '800',
              fontSize: '1.125rem',
              cursor: loading ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '0.75rem',
              transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: loading ? 'none' : '0 15px 30px rgba(99, 102, 241, 0.4)',
              marginTop: '1rem'
            }}
            className="login-btn"
          >
            {loading ? (
              <>
                <div className="loading-spinner" style={{ width: '24px', height: '24px', borderTopColor: 'white' }}></div>
                Authenticating...
              </>
            ) : (
              <>
                <span>Enter Dashboard</span>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
                  <path d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              </>
            )}
          </button>
        </form>

        {error && (
          <div className="fade-in" style={{
            marginTop: '2rem',
            padding: '1.25rem',
            background: 'rgba(244, 63, 94, 0.1)',
            border: '1px solid rgba(244, 63, 94, 0.2)',
            color: '#f43f5e',
            borderRadius: '18px',
            fontSize: '0.9375rem',
            fontWeight: '600',
            textAlign: 'center',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '0.75rem'
          }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
            {error}
          </div>
        )}

        <div style={{
          marginTop: '4rem',
          textAlign: 'center',
          paddingTop: '2rem',
          borderTop: '1px solid rgba(255, 255, 255, 0.05)'
        }}>
          <p style={{ margin: 0, color: '#475569', fontSize: '0.8125rem', fontWeight: '700', letterSpacing: '0.05em', textTransform: 'uppercase' }}>
            Secure Enterprise Portal • v2.0
          </p>
        </div>
      </div>

      <style>{`
        @keyframes float {
          from { transform: translate(0, 0); }
          to { transform: translate(30px, 30px); }
        }
        @keyframes pulse {
          0%, 100% { transform: rotate(-5deg) scale(1); }
          50% { transform: rotate(-5deg) scale(1.05); }
        }
        .login-input:focus {
          border-color: #6366f1 !important;
          background: rgba(0, 0, 0, 0.5) !important;
          box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.15) !important;
        }
        .login-btn:hover:not(:disabled) {
          transform: translateY(-3px) scale(1.02);
          box-shadow: 0 20px 40px rgba(99, 102, 241, 0.5) !important;
        }
        .login-btn:active:not(:disabled) {
          transform: translateY(0) scale(1);
        }
      `}</style>
    </div>
  );
}

export default Login;
